prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?mf ?mfName ?sourceRef ?targetRef ?sourceMatchTask ?targetMatchTask WHERE {
  ?model a bboExt:Model ;
         tai:originalId "01e9c28ede6a4695b91dd90b3e0c5f1b" ;
         tai:belongsTo ?org .

  ?choreo a bboExt:Choreography ; tai:belongsTo ?model .
  ?mf a bboExt:MessageFlow ;
      tai:belongsTo ?choreo ;
      bboExt:sourceRef ?sourceRef ;
      bboExt:targetRef ?targetRef .

  OPTIONAL { ?mf bbo:name ?mfName . }

  OPTIONAL {
    ?task a bboExt:ChoreographyTask ;
          tai:belongsTo ?choreo ;
          FILTER(STRENDS(STR(?task), ?sourceRef))
    BIND(?task AS ?sourceMatchTask)
  }
  OPTIONAL {
    ?task2 a bboExt:ChoreographyTask ;
           tai:belongsTo ?choreo ;
           FILTER(STRENDS(STR(?task2), ?targetRef))
    BIND(?task2 AS ?targetMatchTask)
  }
}
LIMIT 25

