prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?thing ?type ?name WHERE {
  ?model a bboExt:Model ;
         tai:originalId "01e9c28ede6a4695b91dd90b3e0c5f1b" ;
         tai:belongsTo ?org .

  ?thing tai:belongsTo ?choreo .
  ?choreo a bboExt:Choreography .
  FILTER(?thing != ?choreo)

  ?thing a ?type .
  OPTIONAL { ?thing bbo:name ?name . }

  FILTER(
    ?type IN (bboExt:Message, bboExt:MessageFlow, bboExt:Association, bboExt:TextAnnotation)
  )
}
LIMIT 25

